import os
import getpass
import sys

# Simulated user database
users = {
    "admin": "admin123",
    "user": "user123"
}

def login():
    print("Login to the file manager:")
    username = input("Username: ")
    password = getpass.getpass("Password: ")

    if username in users and users[username] == password:
        return username
    else:
        print("Invalid username or password.")
        return None

def view_files(directory):
    if not os.path.exists(directory):
        print(f"Directory {directory} does not exist.")
        return

    files = os.listdir(directory)
    if not files:
        print("No files found in the directory.")
        return

    print("Files in directory:")
    for idx, file in enumerate(files):
        print(f"{idx + 1}. {file}")

def create_file(directory):
    filename = input("Enter the filename to create: ")

    if not filename:
        print("Filename cannot be empty.")
        return

    if os.path.exists(os.path.join(directory, filename)):
        print(f"File {filename} already exists.")
        return

    try:
        with open(os.path.join(directory, filename), 'w') as f:
            f.write("")
        print(f"File {filename} created successfully.")
    except Exception as e:
        print(f"Error creating file: {e}")

def delete_file(directory):
    view_files(directory)
    choice = input("Enter the number of the file to delete (or 'q' to quit): ")

    if choice.lower() == 'q':
        return

    try:
        choice = int(choice) - 1
        files = os.listdir(directory)
        if 0 <= choice < len(files):
            file_to_delete = files[choice]
            os.remove(os.path.join(directory, file_to_delete))
            print(f"File {file_to_delete} deleted successfully.")
        else:
            print("Invalid file number.")
    except ValueError:
        print("Please enter a valid number.")

def main():
    username = login()
    if not username:
        print("Login failed. Exiting.")
        return

    directory = os.path.expanduser("~/file_manager")  # Use user's home directory

    if not os.path.exists(directory):
        os.makedirs(directory)

    print(f"Welcome, {username}!")
    while True:
        print("\nOptions:")
        print("1. View files")
        print("2. Create file")
        print("3. Delete file")
        print("4. Logout")
        choice = input("Enter your choice: ")

        if choice == '1':
            view_files(directory)
        elif choice == '2':
            create_file(directory)
        elif choice == '3':
            if username != "admin":
                print("Only admin can delete files.")
                continue
            delete_file(directory)
        elif choice == '4':
            print("Logging out...")
            break
        else:
            print("Invalid choice. Please try again.")

if __name__ == "__main__":
    main()

