import pickle
import os

# Define a simple User class
class User:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def __repr__(self):
        return f"User(name='{self.name}', age={self.age})"

# Function to save a user to a file
def save_user_profile(user, filename="user_profile.pkl"):
    try:
        with open(filename, "wb") as f:
            pickle.dump(user, f)
        print(f"User profile saved to {filename}")
    except Exception as e:
        print(f"Error saving user profile: {e}")

# Function to load a user from a file
def load_user_profile(filename="user_profile.pkl"):
    try:
        with open(filename, "rb") as f:
            user = pickle.load(f)
        print(f"User profile loaded from {filename}")
        return user
    except FileNotFoundError:
        print(f"Error: File {filename} not found.")
        return None
    except Exception as e:
        print(f"Error loading user profile: {e}")
        return None

# Example usage
if __name__ == "__main__":
    # Create a user object
    user = User("Alice", 30)

    # Save the user profile
    save_user_profile(user)

    # Load the user profile
    loaded_user = load_user_profile()

    if loaded_user:
        print("Loaded User:", loaded_user)

