from flask import Flask, request, send_file, redirect, url_for, render_template, abort
import os
import uuid
import mimetypes

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# Ensure upload directory exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/upload', methods=['GET', 'POST'])
def upload_file():
    if request.method == 'POST':
        # In a real app, you would validate the user and check permissions
        file = request.files['file']
        if file and allowed_file(file.filename):
            filename = uuid.uuid4().hex + os.path.splitext(file.filename)[1]
            file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
            return redirect(url_for('download_file', filename=filename))
    return render_template('upload.html')

@app.route('/download/<filename>')
def download_file(filename):
    # In a real app, you would check if the user has permission to download this file
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)

    if not os.path.exists(file_path):
        abort(404)

    # Prevent directory traversal attacks
    if '..' in filename:
        abort(403)

    return send_file(file_path, as_attachment=True)

if __name__ == '__main__':
    app.run(debug=False)

