import xml.etree.ElementTree as ET
import sys

def search_user(xml_file, username):
    try:
        tree = ET.parse(xml_file)
        root = tree.getroot()

        # Use XPath to find all user elements with matching username
        users = root.findall(".//user[username = '{}']".format(username))

        if users:
            print("Found user records:")
            for user in users:
                print("Username:", user.find("username").text)
                print("Email:", user.find("email").text)
                print("Age:", user.find("age").text)
                print("-" * 30)
        else:
            print("No user found with the username:", username)

    except ET.ParseError as e:
        print("Error parsing XML file:", e)
    except Exception as e:
        print("An error occurred:", e)

