import xml.etree.ElementTree as ET
import sys

def load_music_library(xml_file):
    try:
        tree = ET.parse(xml_file)
        root = tree.getroot()
        songs = []
        for song in root.findall('song'):
            title = song.find('title').text
            artist = song.find('artist').text
            year = song.find('year').text
            songs.append({
                'title': title,
                'artist': artist,
                'year': year
            })
        return songs
    except ET.ParseError:
        print("Error: Invalid XML format.")
        sys.exit(1)
    except FileNotFoundError:
        print(f"Error: File '{xml_file}' not found.")
        sys.exit(1)

def search_by_artist(songs, artist_name):
    return [song for song in songs if song['artist'].lower() == artist_name.lower()]

def main():
    xml_file = 'music_library.xml'
    songs = load_music_library(xml_file)

    artist_name = input("Enter artist name to search for: ").strip()

    if not artist_name:
        print("Error: Artist name cannot be empty.")
        return

    results = search_by_artist(songs, artist_name)

    if not results:
        print(f"No songs found by the artist '{artist_name}'.")
    else:
        print(f"Found {len(results)} songs by {artist_name}:")
        for song in results:
            print(f"- {song['title']} ({song['year']})")

if __name__ == "__main__":
    main()

import os
import logging
from flask import Flask, request, send_from_directory, redirect, url_for, render_template
import uuid

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}

# Ensure the uploads directory exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/', methods=['GET', 'POST'])
def upload_file():
    if request.method == 'POST':
        # Check if the post request has the file part
        if 'file' not in request.files:
            logging.warning("No file part in the request.")
            return redirect(url_for('upload_file'))

        file = request.files['file']

        # If the user doesn't select a file, the browser submits an empty form
        if file.filename == '':
            logging.warning("No selected file.")
            return redirect(url_for('upload_file'))

        if file and allowed_file(file.filename):
            # Generate a unique filename to prevent overwriting
            unique_filename = f"{uuid.uuid4()}_{file.filename}"
            file_path = os.path.join(UPLOAD_FOLDER, unique_filename)
            try:
                file.save(file_path)
                logging.info(f"File uploaded successfully: {file_path}")
                return redirect(url_for('download_file', filename=unique_filename))
            except Exception as e:
                logging.error(f"Error uploading file: {e}")
                return f"Error uploading file: {e}", 500

    return render_template('upload.html')

@app.route('/download/<filename>')
def download_file(filename):
    file_path = os.path.join(UPLOAD_FOLDER, filename)
    if os.path.exists(file_path):
        logging.info(f"File downloaded: {file_path}")
        return send_from_directory(UPLOAD_FOLDER, filename, as_attachment=True)
    else:
        logging.warning(f"File not found: {filename}")
        return "File not found", 404

if __name__ == '__main__':
    app.run(debug=False)

